def factorial_iterative(n):
    result = 1
    for i in range(2, n + 1):
        result *= i
    return result

def factorial_recursive(n):
    if n <= 1:
        return 1
    return n * factorial_recursive(n - 1)

# Test
print(f"5! = {factorial_iterative(5)}")  # 120
print(f"5! = {factorial_recursive(5)}")  # 120

import math

def permutations(n, r):
    """P(n,r) = n! / (n-r)!"""
    return math.factorial(n) // math.factorial(n - r)

def permutations_direct(n, r):
    """P(n,r) = n × (n-1) × ... × (n-r+1)"""
    result = 1
    for i in range(r):
        result *= (n - i)
    return result

# Test
print(f"P(5,3) = {permutations(5, 3)}")   # 60
print(f"P(5,3) = {permutations_direct(5, 3)}")  # 60

import math

def combinations(n, r):
    """C(n,r) = n! / (r! * (n-r)!)"""
    return math.factorial(n) // (math.factorial(r) * math.factorial(n - r))

def combinations_pascal(n, r):
    """Using Pascal's identity: C(n,r) = C(n-1,r-1) + C(n-1,r)"""
    if r == 0 or r == n:
        return 1
    return combinations_pascal(n - 1, r - 1) + combinations_pascal(n - 1, r)

# Test
print(f"C(8,3) = {combinations(8, 3)}")       # 56
print(f"C(8,3) = {combinations_pascal(8, 3)}") # 56
